#include <stdio.h>
#include <stdlib.h>
long long gcd(long long a, long long b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}
long long lcm(long long a, long long b) {
    return (a * b) / gcd(a, b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        long long rebel[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &rebel[i]);
        }
        long long lower, upper;
        scanf("%lld %lld", &lower, &upper);
        long long lcm_rebel = rebel[0];
        for (int i = 1; i < N; i++) {
            lcm_rebel = lcm(lcm_rebel, rebel[i]);
        }
        long long count = 0;
        for (long long i = lower; i <= upper; i++) {
            if (i % lcm_rebel == 0) count++;
        }
        printf("%lld\n", upper - lower + 1 - count);
    }
    return 0;
}

