import java.util.Scanner;
public class Main {
    public static long gcd(long a, long b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
    public static long lcm(long a, long b) {
        return (a * b) / gcd(a, b);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long[] rebel = new long[N];
            for (int i = 0; i < N; i++) {
                rebel[i] = sc.nextLong();
            }
            long lower = sc.nextLong();
            long upper = sc.nextLong();
            long lcm_rebel = rebel[0];
            for (int i = 1; i < N; i++) {
                lcm_rebel = lcm(lcm_rebel, rebel[i]);
            }
            long count = 0;
            for (long i = lower; i <= upper; i++) {
                if (i % lcm_rebel == 0) count++;
            }
            System.out.println(upper - lower + 1 - count);
        }
    }
}

